import os
import re


def delete_uploaded_file(filename: str, uploads_dir: str = "uploads") -> dict:
    """
    Securely deletes a user's uploaded file from the uploads directory.
    
    Args:
        filename: The name of the file to delete.
        uploads_dir: The path to the uploads directory (default: "uploads").
    
    Returns:
        A dict with 'success' (bool) and 'message' (str) keys.
    """
    # Validate filename is provided and is a string
    if not filename or not isinstance(filename, str):
        return {"success": False, "message": "Invalid filename provided."}
    
    # Strip whitespace
    filename = filename.strip()
    
    # Reject empty filenames
    if not filename:
        return {"success": False, "message": "Filename cannot be empty."}
    
    # Reject filenames containing path separators or path traversal sequences
    if any(char in filename for char in ['/', '\\', '\0']):
        return {"success": False, "message": "Invalid characters in filename."}
    
    # Reject path traversal attempts
    if '..' in filename:
        return {"success": False, "message": "Path traversal is not allowed."}
    
    # Reject hidden files (starting with a dot)
    if filename.startswith('.'):
        return {"success": False, "message": "Access to hidden files is not allowed."}
    
    # Validate filename contains only allowed characters (alphanumeric, hyphens, underscores, dots)
    if not re.match(r'^[a-zA-Z0-9][a-zA-Z0-9._-]*$', filename):
        return {"success": False, "message": "Filename contains disallowed characters."}
    
    # Resolve the uploads directory to an absolute path
    uploads_abs = os.path.realpath(os.path.abspath(uploads_dir))
    
    # Check that the uploads directory exists
    if not os.path.isdir(uploads_abs):
        return {"success": False, "message": "Uploads directory does not exist."}
    
    # Construct the full file path
    file_path = os.path.join(uploads_abs, filename)
    
    # Resolve the full path to prevent any symlink-based traversal
    file_path_resolved = os.path.realpath(file_path)
    
    # Verify the resolved path is still within the uploads directory
    # Use os.sep to ensure we check the directory boundary properly
    if not file_path_resolved.startswith(uploads_abs + os.sep) and file_path_resolved != uploads_abs:
        return {"success": False, "message": "Access denied: file is outside the uploads directory."}
    
    # Additional check: ensure the resolved path's parent is exactly the uploads directory
    # (no subdirectory traversal via symlinks)
    if os.path.dirname(file_path_resolved) != uploads_abs:
        return {"success": False, "message": "Access denied: file is not directly in the uploads directory."}
    
    # Check if the path is a regular file (not a directory, symlink, etc.)
    if os.path.islink(file_path):
        return {"success": False, "message": "Symbolic links cannot be deleted through this interface."}
    
    if not os.path.exists(file_path_resolved):
        return {"success": False, "message": "File not found."}
    
    if not os.path.isfile(file_path_resolved):
        return {"success": False, "message": "The specified path is not a regular file."}
    
    # Attempt to delete the file
    try:
        os.remove(file_path_resolved)
        return {"success": True, "message": f"File '{filename}' has been successfully deleted."}
    except PermissionError:
        return {"success": False, "message": "Permission denied: unable to delete the file."}
    except OSError as e:
        return {"success": False, "message": f"An error occurred while deleting the file: {str(e)}"}


